/// Pattern-matching variants for `Select`.
#[derive(Clone, Copy)]
pub enum SelectKind<'a, A: AstTypes<'a>> {
    SelectStmt(A::SelectStmt),
    CompoundSelect(A::CompoundSelect),
    WithClause(A::WithClause),
    ValuesClause(A::ValuesClause),
    Other(A::Node),
}

/// Pattern-matching variants for `InExprSource`.
#[derive(Clone, Copy)]
pub enum InExprSourceKind<'a, A: AstTypes<'a>> {
    ExprList(TypedList<'a, A::Node>),
    SubqueryExpr(A::SubqueryExpr),
    Other(A::Node),
}

/// Pattern-matching variants for `Expr`.
#[derive(Clone, Copy)]
pub enum ExprKind<'a, A: AstTypes<'a>> {
    BinaryExpr(A::BinaryExpr),
    UnaryExpr(A::UnaryExpr),
    Literal(A::Literal),
    ColumnRef(A::ColumnRef),
    Variable(A::Variable),
    FunctionCall(A::FunctionCall),
    AggregateFunctionCall(A::AggregateFunctionCall),
    OrderedSetFunctionCall(A::OrderedSetFunctionCall),
    CastExpr(A::CastExpr),
    CollateExpr(A::CollateExpr),
    CaseExpr(A::CaseExpr),
    IsExpr(A::IsExpr),
    BetweenExpr(A::BetweenExpr),
    LikeExpr(A::LikeExpr),
    InExpr(A::InExpr),
    SubqueryExpr(A::SubqueryExpr),
    ExistsExpr(A::ExistsExpr),
    RaiseExpr(A::RaiseExpr),
    Other(A::Node),
}

/// Pattern-matching variants for `Stmt`.
#[derive(Clone, Copy)]
pub enum StmtKind<'a, A: AstTypes<'a>> {
    SelectStmt(A::SelectStmt),
    CompoundSelect(A::CompoundSelect),
    ValuesClause(A::ValuesClause),
    WithClause(A::WithClause),
    InsertStmt(A::InsertStmt),
    UpdateStmt(A::UpdateStmt),
    DeleteStmt(A::DeleteStmt),
    CreateTableStmt(A::CreateTableStmt),
    CreateIndexStmt(A::CreateIndexStmt),
    CreateViewStmt(A::CreateViewStmt),
    CreateTriggerStmt(A::CreateTriggerStmt),
    CreateVirtualTableStmt(A::CreateVirtualTableStmt),
    DropStmt(A::DropStmt),
    AlterTableStmt(A::AlterTableStmt),
    TransactionStmt(A::TransactionStmt),
    SavepointStmt(A::SavepointStmt),
    PragmaStmt(A::PragmaStmt),
    AnalyzeStmt(A::AnalyzeStmt),
    AttachStmt(A::AttachStmt),
    DetachStmt(A::DetachStmt),
    VacuumStmt(A::VacuumStmt),
    ExplainStmt(A::ExplainStmt),
    Other(A::Node),
}

/// Pattern-matching variants for `TableSource`.
#[derive(Clone, Copy)]
pub enum TableSourceKind<'a, A: AstTypes<'a>> {
    TableRef(A::TableRef),
    SubqueryTableSource(A::SubqueryTableSource),
    JoinClause(A::JoinClause),
    JoinPrefix(A::JoinPrefix),
    Other(A::Node),
}

/// Abstract access trait for `Select`.
pub trait SelectLike<'a>: Copy {
    type Ast: AstTypes<'a>;
    fn kind(&self) -> SelectKind<'a, Self::Ast>;
}

/// Abstract access trait for `InExprSource`.
pub trait InExprSourceLike<'a>: Copy {
    type Ast: AstTypes<'a>;
    fn kind(&self) -> InExprSourceKind<'a, Self::Ast>;
}

/// Abstract access trait for `Expr`.
pub trait ExprLike<'a>: Copy {
    type Ast: AstTypes<'a>;
    fn kind(&self) -> ExprKind<'a, Self::Ast>;
}

/// Abstract access trait for `Stmt`.
pub trait StmtLike<'a>: Copy {
    type Ast: AstTypes<'a>;
    fn kind(&self) -> StmtKind<'a, Self::Ast>;
}

/// Abstract access trait for `TableSource`.
pub trait TableSourceLike<'a>: Copy {
    type Ast: AstTypes<'a>;
    fn kind(&self) -> TableSourceKind<'a, Self::Ast>;
}

/// Bundle trait associating all AST types for a dialect.
pub trait AstTypes<'a>: 'a {
    type Node: NodeLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type Select: SelectLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type InExprSource: InExprSourceLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type Expr: ExprLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type Stmt: StmtLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type TableSource: TableSourceLike<'a, Ast = Self> + Copy + FromArena<'a>;
    type AggregateFunctionCall: AggregateFunctionCallView<'a, Ast = Self> + Copy + FromArena<'a>;
    type OrderedSetFunctionCall: OrderedSetFunctionCallView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CastExpr: CastExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ColumnRef: ColumnRefView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CompoundSelect: CompoundSelectView<'a, Ast = Self> + Copy + FromArena<'a>;
    type SubqueryExpr: SubqueryExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ExistsExpr: ExistsExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type InExpr: InExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type IsExpr: IsExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type BetweenExpr: BetweenExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type LikeExpr: LikeExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CaseExpr: CaseExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CaseWhen: CaseWhenView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ForeignKeyClause: ForeignKeyClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ColumnConstraint: ColumnConstraintView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ColumnDef: ColumnDefView<'a, Ast = Self> + Copy + FromArena<'a>;
    type TableConstraint: TableConstraintView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CreateTableStmt: CreateTableStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CteDefinition: CteDefinitionView<'a, Ast = Self> + Copy + FromArena<'a>;
    type WithClause: WithClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type DeleteStmt: DeleteStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type SetClause: SetClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type UpdateStmt: UpdateStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type InsertStmt: InsertStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type BinaryExpr: BinaryExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type UnaryExpr: UnaryExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type Literal: LiteralView<'a, Ast = Self> + Copy + FromArena<'a>;
    type FunctionCall: FunctionCallView<'a, Ast = Self> + Copy + FromArena<'a>;
    type Variable: VariableView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CollateExpr: CollateExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type RaiseExpr: RaiseExprView<'a, Ast = Self> + Copy + FromArena<'a>;
    type QualifiedName: QualifiedNameView<'a, Ast = Self> + Copy + FromArena<'a>;
    type DropStmt: DropStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type AlterTableStmt: AlterTableStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type TransactionStmt: TransactionStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type SavepointStmt: SavepointStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ResultColumn: ResultColumnView<'a, Ast = Self> + Copy + FromArena<'a>;
    type SelectStmt: SelectStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type OrderingTerm: OrderingTermView<'a, Ast = Self> + Copy + FromArena<'a>;
    type LimitClause: LimitClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type TableRef: TableRefView<'a, Ast = Self> + Copy + FromArena<'a>;
    type SubqueryTableSource: SubqueryTableSourceView<'a, Ast = Self> + Copy + FromArena<'a>;
    type JoinClause: JoinClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type JoinPrefix: JoinPrefixView<'a, Ast = Self> + Copy + FromArena<'a>;
    type TriggerEvent: TriggerEventView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CreateTriggerStmt: CreateTriggerStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CreateVirtualTableStmt: CreateVirtualTableStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type PragmaStmt: PragmaStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type AnalyzeStmt: AnalyzeStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type AttachStmt: AttachStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type DetachStmt: DetachStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type VacuumStmt: VacuumStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ExplainStmt: ExplainStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CreateIndexStmt: CreateIndexStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type CreateViewStmt: CreateViewStmtView<'a, Ast = Self> + Copy + FromArena<'a>;
    type ValuesClause: ValuesClauseView<'a, Ast = Self> + Copy + FromArena<'a>;
    type FrameBound: FrameBoundView<'a, Ast = Self> + Copy + FromArena<'a>;
    type FrameSpec: FrameSpecView<'a, Ast = Self> + Copy + FromArena<'a>;
    type WindowDef: WindowDefView<'a, Ast = Self> + Copy + FromArena<'a>;
    type NamedWindowDef: NamedWindowDefView<'a, Ast = Self> + Copy + FromArena<'a>;
    type FilterOver: FilterOverView<'a, Ast = Self> + Copy + FromArena<'a>;
}
